import React from 'react';
import FullWidthPageLayout from '@layouts/FullWidthPage';
import PricingCards from '@components/PricingCards';
import { PricingComparisonWithChai } from '@components/PricingComparisonWithObjects';
import Seo from '@components/Seo';

export default function PricingPage() {
	return (
		<FullWidthPageLayout>
			<h1 style={{ textAlign: 'center', marginBottom: 0 }}>
				Plans &amp; <span>Pricing</span>
			</h1>
			<PricingCards />
			<PricingComparisonWithChai />
		</FullWidthPageLayout>
	);
}

export function Head({ location }) {
	return (
		<Seo
			title="Pricing"
			description="Kaagzi is offered in 3 tenure plans starting at INR 75. Kaagzi costs less than your everyday cup of tea."
			urlPath={'/' + location.pathname}
		/>
	);
}
